\n24\\t///     id         TEXT NOT NULL,\\n25\\t///     version    INTEGER NOT NULL,\\n26\\t///     data       TEXT NOT NULL,\\n27\\t///     PRIMARY KEY (collection, id)\\n28\\t/// );\\n29\\t/// ```\\n30\\t///\\n31\\t/// Transactions use SQLite's `BEGIN IMMEDIATE` / `COMMIT` / `ROLLBACK`\\n32\\t/// statements. `BEGIN IMMEDIATE` acquires a write lock up-front, eliminating\\n33\\t/// the TOCTOU window that exists when a read and write are issued as separate\\n34\\t/// statements.\\n35\\tpub struct SqliteStorageAdapter {\\n36\\t    conn: Mutex\u003cConnection\u003e,\\n37\\t    /// `true` while a `BEGIN` has been issued but not yet committed or rolled back.\\n38\\t    in_tx: bool,\\n39\\t}\\n40\\t\\n41\\timpl SqliteStorageAdapter {\\n42\\t    /// Opens (or creates) a SQLite database at the given path.\\n43\\t    pub fn open(path: \u0026str) -\u003e Result\u003cSelf, AxonError\u003e {\\n44\\t        let conn = Connection::open(path).map_err(|e| AxonError::Storage(e.to_string()))?;\\n45\\t        let adapter = Self {\\n46\\t            conn: Mutex::new(conn),\\n47\\t            in_tx: false,\\n48\\t        };\\n49\\t        adapter.init_schema()?;\\n50\\t        Ok(adapter)\\n51\\t    }\\n52\\t\\n53\\t    /// Opens an in-memory SQLite database (useful for testing).\\n54\\t    pub fn open_in_memory() -\u003e Result\u003cSelf, AxonError\u003e {\\n55\\t        let conn = Connection::open_in_memory().map_err(|e| AxonError::Storage(e.to_string()))?;\\n56\\t        let adapter = Self {\\n57\\t            conn: Mutex::new(conn),\\n58\\t            in_tx: false,\\n59\\t        };\\n60\\t        adapter.init_schema()?;\\n61\\t        Ok(adapter)\\n62\\t    }\\n63\\t\\n64\\t    /// Acquire the inner `Connection` lock, converting a poisoned-mutex error into\\n65\\t    /// an `AxonError::Storage`.\\n66\\t    fn conn(\u0026self) -\u003e Result\u003cMutexGuard\u003c'_, Connection\u003e, AxonError\u003e {\\n67\\t        self.conn\\n68\\t            .lock()\\n69\\t            .map_err(|e| AxonError::Storage(format!(\\\"mutex poisoned: {e}\\\")))\\n70\\t    }\\n71\\t\\n72\\t    fn init_schema(\u0026self) -\u003e Result\u003c(), AxonError\u003e {\\n73\\t        self.conn()?\\n74\\t            .execute_batch(\\n75\\t                \\\"PRAGMA foreign_keys = ON;\\n76\\t                CREATE TABLE IF NOT EXISTS databases (\\n77\\t                    name TEXT NOT NULL PRIMARY KEY\\n78\\t                );\\n79\\t                CREATE TABLE IF NOT EXISTS namespaces (\\n80\\t                    database_name TEXT NOT NULL,\\n81\\t                    name          TEXT NOT NULL,\\n82\\t                    PRIMARY KEY (database_name, name),\\n83\\t                    FOREIGN KEY (database_name) REFERENCES databases(name) ON DELETE CASCADE\\n84\\t                );\\n85\\t                CREATE TABLE IF NOT EXISTS entities (\\n86\\t                    collection    TEXT NOT NULL,\\n87\\t                    database_name TEXT NOT NULL DEFAULT 'default',\\n88\\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\\n89\\t                    id            TEXT NOT NULL,\\n90\\t                    version       INTEGER NOT NULL,\\n91\\t                    data          TEXT NOT NULL,\\n92\\t                    PRIMARY KEY (database_name, schema_name, collection, id)\\n93\\t                );\\n94\\t                CREATE TABLE IF NOT EXISTS schema_versions (\\n95\\t                    collection    TEXT NOT NULL,\\n96\\t                    database_name TEXT NOT NULL DEFAULT 'default',\\n97\\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\\n98\\t                    version       INTEGER NOT NULL,\\n99\\t                    schema_json   TEXT NOT NULL,\\n100\\t                    created_at    INTEGER NOT NULL DEFAULT 0,\\n101\\t                    PRIMARY KEY (database_name, schema_name, collection, version)\\n102\\t                );\\n103\\t                CREATE TABLE IF NOT EXISTS collections (\\n104\\t                    name          TEXT NOT NULL,\\n105\\t                    database_name TEXT NOT NULL DEFAULT 'default',\\n106\\t                    schema_name   TEXT NOT NULL DEFAULT 'default',\\n107\\t                    PRIMARY KEY (database_name, schema_name, name)\\n108\\t                );\\n109\\t                CREATE TABLE IF NOT EXISTS collection_views (\\n110\\t                    collection        TEXT NOT NULL,\\n111\\t                    database_name     TEXT NOT NULL DEFAULT 'default',\\n112\\t                    schema_name       TEXT NOT NULL DEFAULT 'default',\\n113\\t                    version           INTEGER NOT NULL,\\n114\\t                    view_json         TEXT NOT NULL,\\n115\\t                    updated_at_ns     INTEGER NOT NULL,\\n116\\t                    updated_by        TEXT,\\n117\\t                    PRIMARY KEY (database_name, schema_name, collection),\\n118\\t                    FOREIGN KEY (database_name, schema_name, collection)\\n119\\t                        REFERENCES collections(database_name, schema_name, name)\\n120\\t                        ON DELETE CASCADE\\n121\\t                );\\n122\\t                CREATE TABLE IF NOT EXISTS audit_log (\\n123\\t                    id             INTEGER PRIMARY KEY AUTOINCREMENT,\\n124\\t                    timestamp_ns   INTEGER NOT NULL,\\n125\\t                    collection     TEXT NOT NULL,\\n126\\t                    entity_id      TEXT NOT NULL,\\n127\\t                    version        INTEGER NOT NULL,\\n128\\t                    mutation       TEXT NOT NULL,\\n129\\t                    actor          TEXT NOT NULL,\\n130\\t                    transaction_id TEXT,\\n131\\t                    entry_json     TEXT NOT NULL\\n132\\t                );\\\",\\n133\\t            )\\n134\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n135\\t        self.ensure_namespace_catalog_tables()?;\\n136\\t        self.ensure_default_namespace()\\n137\\t    }\\n138\\t\\n139\\t    fn collection_exists_in_namespace(\\n140\\t        \u0026self,\\n141\\t        collection: \u0026CollectionId,\\n142\\t        namespace: \u0026Namespace,\\n143\\t    ) -\u003e Result\u003cbool, AxonError\u003e {\\n144\\t        let exists: i64 = self\\n145\\t            .conn()?\\n146\\t            .query_row(\\n147\\t                \\\"SELECT EXISTS(\\n148\\t                    SELECT 1 FROM collections\\n149\\t                    WHERE name = ?1 AND database_name = ?2 AND schema_name = ?3\\n150\\t                )\\\",\\n151\\t                params![\\n152\\t                    collection.as_str(),\\n153\\t                    namespace.database.as_str(),\\n154\\t                    namespace.schema.as_str()\\n155\\t                ],\\n156\\t                |row| row.get(0),\\n157\\t            )\\n158\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n159\\t        Ok(exists != 0)\\n160\\t    }\\n161\\t\\n162\\t    fn database_exists(\u0026self, database: \u0026str) -\u003e Result\u003cbool, AxonError\u003e {\\n163\\t        let exists: i64 = self\\n164\\t            .conn()?\\n165\\t            .query_row(\\n166\\t                \\\"SELECT EXISTS(SELECT 1 FROM databases WHERE name = ?1)\\\",\\n167\\t                params![database],\\n168\\t                |row| row.get(0),\\n169\\t            )\\n170\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n171\\t        Ok(exists != 0)\\n172\\t    }\\n173\\t\\n174\\t    fn namespace_exists(\u0026self, namespace: \u0026Namespace) -\u003e Result\u003cbool, AxonError\u003e {\\n175\\t        let exists: i64 = self\\n176\\t            .conn()?\\n177\\t            .query_row(\\n178\\t                \\\"SELECT EXISTS(\\n179\\t                    SELECT 1 FROM namespaces\\n180\\t                    WHERE database_name = ?1 AND name = ?2\\n181\\t                )\\\",\\n182\\t                params![namespace.database.as_str(), namespace.schema.as_str()],\\n183\\t                |row| row.get(0),\\n184\\t            )\\n185\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n186\\t        Ok(exists != 0)\\n187\\t    }\\n188\\t\\n189\\t    fn table_info(\u0026self, table: \u0026str) -\u003e Result\u003cVec\u003c(String, i64)\u003e, AxonError\u003e {\\n190\\t        let conn = self.conn()?;\\n191\\t        let mut stmt = conn\\n192\\t            .prepare(\u0026format!(\\\"PRAGMA table_info({table})\\\"))\\n193\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n194\\t        let rows = stmt\\n195\\t            .query_map([], |row| {\\n196\\t                Ok((row.get::\u003c_, String\u003e(1)?, row.get::\u003c_, i64\u003e(5)?))\\n197\\t            })\\n198\\t            .map_err(|e| AxonError::Storage(e.to_string()))?\\n199\\t            .collect::\u003cResult\u003cVec\u003c_\u003e, _\u003e\u003e()\\n200\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n201\\t        Ok(rows)\\n202\\t    }\\n203\\t\\n204\\t    fn table_columns(\u0026self, table: \u0026str) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n205\\t        self.table_info(table)\\n206\\t            .map(|rows| rows.into_iter().map(|(name, _)| name).collect())\\n207\\t    }\\n208\\t\\n209\\t    fn table_pk_columns(\u0026self, table: \u0026str) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n210\\t        let mut rows = self.table_info(table)?;\\n211\\t        rows.retain(|(_, pk)| *pk \u003e 0);\\n212\\t        rows.sort_by_key(|(_, pk)| *pk);\\n213\\t        Ok(rows.into_iter().map(|(name, _)| name).collect())\\n214\\t    }\\n215\\t\\n216\\t    fn rebuild_collections_table(\\n217\\t        \u0026self,\\n218\\t        has_database_name: bool,\\n219\\t        has_schema_name: bool,\\n220\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n221\\t        self.conn()?\\n222\\t            .execute_batch(\\n223\\t                \\\"ALTER TABLE collections RENAME TO collections_legacy;\\n224\\t                 CREATE TABLE collections (\\n225\\t                     name          TEXT NOT NULL,\\n226\\t                     database_name TEXT NOT NULL DEFAULT 'default',\\n227\\t                     schema_name   TEXT NOT NULL DEFAULT 'default',\\n228\\t                     PRIMARY KEY (database_name, schema_name, name)\\n229\\t                 );\\\",\\n230\\t            )\\n231\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n232\\t\\n233\\t        let select_sql = match (has_database_name, has_schema_name) {\\n234\\t            (true, true) =\u003e {\\n235\\t                \\\"SELECT name, COALESCE(database_name, 'default'), COALESCE(schema_name, 'default')\\n236\\t                 FROM collections_legacy\\\"\\n237\\t            }\\n238\\t            (true, false) =\u003e {\\n239\\t                \\\"SELECT name, COALESCE(database_name, 'default'), 'default'\\n240\\t                 FROM collections_legacy\\\"\\n241\\t            }\\n242\\t            (false, true) =\u003e {\\n243\\t                \\\"SELECT name, 'default', COALESCE(schema_name, 'default')\\n244\\t                 FROM collections_legacy\\\"\\n245\\t            }\\n246\\t            (false, false) =\u003e {\\n247\\t                \\\"SELECT name, 'default', 'default'\\n248\\t                 FROM collections_legacy\\\"\\n249\\t            }\\n250\\t        };\\n251\\t\\n252\\t        self.conn()?\\n253\\t            .execute(\\n254\\t                \u0026format!(\\n255\\t                    \\\"INSERT OR IGNORE INTO collections (name, database_name, schema_name) {select_sql}\\\"\\n256\\t                ),\\n257\\t                [],\\n258\\t            )\\n259\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n260\\t        self.conn()?\\n261\\t            .execute(\\\"DROP TABLE collections_legacy\\\", [])\\n262\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n263\\t        Ok(())\\n264\\t    }\\n265\\t\\n266\\t    fn rebuild_entities_table(\\n267\\t        \u0