\\t                )\\n381\\t            })\\n382\\t            .collect())\\n383\\t    }\\n384\\t\\n385\\t    fn ensure_default_namespace(\u0026self) -\u003e Result\u003c(), AxonError\u003e {\\n386\\t        self.block(self.client.execute(\\n387\\t            \\\"INSERT INTO databases (name) VALUES ($1) ON CONFLICT DO NOTHING\\\",\\n388\\t            \u0026[\u0026DEFAULT_DATABASE],\\n389\\t        ))?;\\n390\\t        self.block(self.client.execute(\\n391\\t            \\\"INSERT INTO namespaces (database_name, name)\\n392\\t                 VALUES ($1, $2)\\n393\\t                 ON CONFLICT DO NOTHING\\\",\\n394\\t            \u0026[\u0026DEFAULT_DATABASE, \u0026DEFAULT_SCHEMA],\\n395\\t        ))?;\\n396\\t        Ok(())\\n397\\t    }\\n398\\t\\n399\\t    fn row_to_entity(row: \u0026tokio_postgres::Row) -\u003e Result\u003cEntity, AxonError\u003e {\\n400\\t        let collection: String = row.get(\\\"collection\\\");\\n401\\t        let id: String = row.get(\\\"id\\\");\\n402\\t        let version: i64 = row.get(\\\"version\\\");\\n403\\t        let data: serde_json::Value = row.get(\\\"data\\\");\\n404\\t        Ok(Entity {\\n405\\t            collection: CollectionId::new(collection),\\n406\\t            id: EntityId::new(id),\\n407\\t            version: version as u64,\\n408\\t            data,\\n409\\t            created_at_ns: None,\\n410\\t            updated_at_ns: None,\\n411\\t            created_by: None,\\n412\\t            updated_by: None,\\n413\\t            schema_version: None,\\n414\\t            gate_results: Default::default(),\\n415\\t        })\\n416\\t    }\\n417\\t}\\n418\\t\\n419\\timpl StorageAdapter for PostgresStorageAdapter {\\n420\\t    fn resolve_collection_key(\\n421\\t        \u0026self,\\n422\\t        collection: \u0026CollectionId,\\n423\\t    ) -\u003e Result\u003cQualifiedCollectionId, AxonError\u003e {\\n424\\t        self.resolve_catalog_key(collection)\\n425\\t    }\\n426\\t\\n427\\t    fn get(\u0026self, collection: \u0