 31	func (s *passthroughTestService) Execute(ctx context.Context, req agentlib.ServiceExecuteRequest) (<-chan agentlib.ServiceEvent, error) {
 32		s.executeCalled = true
 33		s.lastReq = req
 34		ch := make(chan agentlib.ServiceEvent, len(s.executeEvents)+1)
 35		if len(s.executeEvents) > 0 {
 36			for _, evt := range s.executeEvents {
 37				ch <- evt
 38			}
 39		} else {
 40			ch <- agentlib.ServiceEvent{Type: "final", Data: []byte(`{"status":"success","final_text":"ok"}`)}
 41		}
 42		close(ch)
 43		return ch, nil
 44	}
