109	// resolvedWithPassthrough builds a sealed ResolvedConfig with the given
110	// harness/provider/model/minPower/maxPower and no other overrides.
111	func resolvedWithPassthrough(harness, provider, model string, minPower, maxPower int) config.ResolvedConfig {
112		cfg := config.NewTestConfigForRun(config.TestRunConfigOpts{
113			Harness: harness,
114			Model:   model,
115		})
116		return cfg.Resolve(config.CLIOverrides{
117			Provider: provider,
118			MinPower: minPower,
119			MaxPower: maxPower,
120		})
121	}
