165	// TestExecuteOnService_InvalidPassthroughNotPrevalidated (AC6): DDx must NOT
166	// reject an obviously bogus harness/provider/model before forwarding to the
167	// service. The service is the authoritative validator.
168	func TestExecuteOnService_InvalidPassthroughNotPrevalidated(t *testing.T) {
169		svc := &passthroughTestService{}
170		rcfg := resolvedWithPassthrough("definitely-not-a-real-harness!!!", "bogus-provider", "bogus-model-xyz", 0, 0)
171	
172		_, err := executeOnService(context.Background(), svc, t.TempDir(), rcfg, AgentRunRuntime{
173			Prompt: "hello",
174		})
175		// DDx must not return an error from pre-validation; the service stub
176		// returns success so we expect no error here.
177		if err != nil {
178			t.Errorf("DDx pre-validated passthrough and returned error (must not): %v", err)
179		}
180		if !svc.executeCalled {
181			t.Error("Execute was never called — DDx must forward invalid passthrough to service unchanged")
182		}
183		if svc.lastReq.Harness != "definitely-not-a-real-harness!!!" {
184			t.Errorf("Harness was mutated before forwarding: got %q", svc.lastReq.Harness)
185		}
186		if svc.lastReq.Provider != "bogus-provider" {
187			t.Errorf("Provider was mutated before forwarding: got %q", svc.lastReq.Provider)
188		}
189		if svc.lastReq.Model != "bogus-model-xyz" {
190			t.Errorf("Model was mutated before forwarding: got %q", svc.lastReq.Model)
191		}
192	}
