179	// drainServiceEvents reads service events and returns the final-event payload,
180	// the routing decision (when present in the routing_decision start event), and
181	// any canonical progress payloads emitted by the service.
182	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
183		var final *agentlib.ServiceFinalData
184		var routing *agentlib.ServiceRoutingDecisionData
185		var progress []agentlib.ServiceProgressData
186	
187		for ev := range events {
188			decoded, err := agentlib.DecodeServiceEvent(ev)
189			if err != nil {
190				continue
191			}
192			switch {
193			case decoded.RoutingDecision != nil:
194				routing = decoded.RoutingDecision
195			case decoded.Progress != nil:
196				progress = append(progress, *decoded.Progress)
197			case decoded.Final != nil:
198				final = decoded.Final
199			}
200		}
201		return final, routing, progress
202	}
