 75			canonicalTarget = opts.Model
 76		}
 77		if canonicalTarget == "" && harness.DefaultModel != "" {
 78			canonicalTarget = harness.DefaultModel
 79		}
 80		if canonicalTarget == "" {
 81			canonicalTarget = result.Harness
 82		}
 83	
 84		outcome := RoutingOutcome{
 85			Harness:         result.Harness,
 86			Surface:         harness.Surface,
 87			CanonicalTarget: canonicalTarget,
 88			Model:           result.Model,
 89			ObservedAt:      time.Now().UTC(),
 90			Success:         result.ExitCode == 0 && result.Error == "",
 91			LatencyMS:       int(elapsed.Milliseconds()),
 92			InputTokens:     result.InputTokens,
 93			OutputTokens:    result.OutputTokens,
 94			CostUSD:         result.CostUSD,
 95			NativeSessionID: result.AgentSessionID,
 96		}
 97	
 98		if opts.Correlation != nil {
 99			outcome.TraceID = opts.Correlation["trace_id"]
100			outcome.SpanID = opts.Correlation["span_id"]
101			if outcome.NativeSessionID == "" {
102				outcome.NativeSessionID = opts.Correlation["native_session_id"]
103			}
104			if outcome.NativeLogRef == "" {
105				outcome.NativeLogRef = opts.Correlation["native_log_ref"]
106			}
107		}
108	
109		_ = NewRoutingMetricsStore(r.Config.SessionLogDir).AppendOutcome(outcome)
110	}
